import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useToast } from '../../context/ToastContext';

const Logo = () => (
  <div style={{display:'flex',alignItems:'center',gap:12,justifyContent:'center',marginBottom:24}}>
    <div style={{width:42,height:42,background:'var(--g-brand)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',boxShadow:'0 6px 20px rgba(99,102,241,.5)'}}>
      <span style={{color:'#fff',fontFamily:'var(--ff-h)',fontWeight:800,fontSize:21}}>D</span>
    </div>
    <span style={{fontFamily:'var(--ff-h)',fontWeight:800,fontSize:22,letterSpacing:'-0.03em'}}>DeLaxiY</span>
  </div>
);

function checkField(key, value, extra) {
  switch(key) {
    case 'name':
      if (!value.trim())        return 'Please fill the field';
      if (value.trim().length < 2) return 'Name must be at least 2 characters';
      return '';
    case 'email':
      if (!value.trim())        return 'Please fill the field';
      if (!/^[^@]+@[^@]+\.[^@]+$/.test(value)) return 'Enter a valid email address';
      return '';
    case 'password':
      if (!value)               return 'Please fill the field';
      if (value.length < 6)     return 'Minimum 6 characters required';
      return '';
    case 'confirm':
      if (!value)               return 'Please fill the field';
      if (value !== extra)      return 'Passwords do not match';
      return '';
    default: return '';
  }
}

export default function AuthModal({ mode, onClose, onSwitch }) {
  const { login, register, loading } = useAuth();
  const { add }    = useToast();
  const navigate   = useNavigate();

  const [name,     setName]     = useState('');
  const [email,    setEmail]    = useState('');
  const [password, setPassword] = useState('');
  const [confirm,  setConfirm]  = useState('');
  const [errs,     setErrs]     = useState({});
  const [touched,  setTouched]  = useState({});
  const [show,     setShow]     = useState(false);
  const [showC,    setShowC]    = useState(false);

  /* ── real-time onChange handlers ── */
  const onName = e => {
    const v = e.target.value; setName(v);
    setTouched(p=>({...p,name:true}));
    setErrs(p=>({...p, name:checkField('name',v), _:null}));
  };
  const onEmail = e => {
    const v = e.target.value; setEmail(v);
    setTouched(p=>({...p,email:true}));
    setErrs(p=>({...p, email:checkField('email',v), _:null}));
  };
  const onPassword = e => {
    const v = e.target.value; setPassword(v);
    setTouched(p=>({...p,password:true}));
    setErrs(p=>({
      ...p,
      password: checkField('password',v),
      confirm:  touched.confirm ? checkField('confirm',confirm,v) : p.confirm,
      _: null,
    }));
  };
  const onConfirm = e => {
    const v = e.target.value; setConfirm(v);
    setTouched(p=>({...p,confirm:true}));
    setErrs(p=>({...p, confirm:checkField('confirm',v,password), _:null}));
  };

  /* ── submit ── */
  async function submit(e) {
    e.preventDefault();
    setTouched({name:true,email:true,password:true,confirm:true});
    const ev = {};
    if (mode==='register') { const n=checkField('name',name);       if(n) ev.name=n; }
    const em=checkField('email',email);                               if(em) ev.email=em;
    const pw=checkField('password',password);                         if(pw) ev.password=pw;
    if (mode==='register') { const cf=checkField('confirm',confirm,password); if(cf) ev.confirm=cf; }
    if (Object.keys(ev).length) { setErrs(ev); return; }
    try {
      if (mode==='login') await login(email, password);
      else                await register(name, email, password);
      add(mode==='login'?'🎉 Welcome back!':'🚀 Account created!','success');
      onClose(); navigate('/dashboard');
    } catch(err) { setErrs({_:err.message}); }
  }

  /* ── styles ── */
  const IS = (hasErr, isOk) => ({
    background:'rgba(255,255,255,0.05)',
    border:`1.5px solid ${hasErr?'#f43f5e':isOk?'#10b981':'var(--border2)'}`,
    borderRadius:'var(--r2)', padding:'11px 15px',
    color:'var(--t1)', fontFamily:'var(--ff-b)', fontSize:'14px',
    width:'100%', outline:'none', transition:'border-color .2s, box-shadow .2s',
    boxSizing:'border-box',
  });

  /* ── password strength ── */
  const strength = !password ? 0
    : password.length < 6  ? 1
    : password.length < 10 ? 2
    : /[A-Z]/.test(password)&&/[0-9]/.test(password) ? 4 : 3;
  const sColor = ['transparent','#f43f5e','#f59e0b','#06b6d4','#10b981'][strength];
  const sLabel = ['','Weak','Fair','Good','Strong'][strength];

  /* ── field wrapper ── */
  const F = ({id, label, err, ok, children}) => (
    <div style={{display:'flex',flexDirection:'column',gap:5}}>
      <label htmlFor={id} style={{fontSize:'11px',fontWeight:700,color:'var(--t2)',textTransform:'uppercase',letterSpacing:'.05em'}}>{label}</label>
      {children}
      {err
        ? <span style={{fontSize:'12px',color:'#f43f5e',display:'flex',alignItems:'center',gap:4,fontWeight:500}}><span style={{fontSize:9}}>●</span>{err}</span>
        : ok
        ? <span style={{fontSize:'12px',color:'#10b981',display:'flex',alignItems:'center',gap:4}}><span>✓</span>{ok}</span>
        : null
      }
    </div>
  );

  return (
    <div className="overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal modal-sm scale-in" onClick={e=>e.stopPropagation()}>
        <div style={{height:4,background:'var(--g-brand)',borderRadius:'var(--r4) var(--r4) 0 0'}}/>

        <div style={{padding:'30px 32px 24px'}}>
          <Logo/>

          <div style={{textAlign:'center',marginBottom:22}}>
            <h2 style={{fontSize:20,marginBottom:5}}>{mode==='login'?'Welcome back':'Create account'}</h2>
            <p style={{fontSize:13,color:'var(--t2)'}}>{mode==='login'?'Sign in to your DeLaxiY account':'Start managing orders and dashboards'}</p>
          </div>

          {errs._ && (
            <div style={{background:'rgba(244,63,94,.12)',border:'1px solid rgba(244,63,94,.3)',borderRadius:'var(--r2)',padding:'10px 14px',color:'#f43f5e',fontSize:13,marginBottom:14,display:'flex',alignItems:'center',gap:8}}>
              <span>✕</span>{errs._}
            </div>
          )}

          <form onSubmit={submit} style={{display:'flex',flexDirection:'column',gap:14}} noValidate autoComplete="on">

            {/* Full Name */}
            {mode==='register' && (
              <F id="am-name" label="Full Name"
                err={touched.name && errs.name}
                ok={touched.name && !errs.name && name ? 'Looks good!' : ''}>
                <input id="am-name" name="fullname" type="text" placeholder="Enter your full name"
                  value={name} onChange={onName} onBlur={()=>setTouched(p=>({...p,name:true}))}
                  style={IS(touched.name&&errs.name, touched.name&&!errs.name&&name)}
                  autoComplete="name" autoFocus/>
              </F>
            )}

            {/* Email */}
            <F id="am-email" label="Email Address"
              err={touched.email && errs.email}
              ok={touched.email && !errs.email && email ? 'Valid email ✓' : ''}>
              <input id="am-email" name="email" type="email" placeholder="you@example.com"
                value={email} onChange={onEmail} onBlur={()=>setTouched(p=>({...p,email:true}))}
                style={IS(touched.email&&errs.email, touched.email&&!errs.email&&email)}
                autoComplete="email"/>
            </F>

            {/* Password */}
            <F id="am-pwd" label="Password"
              err={touched.password && errs.password}>
              <div style={{position:'relative'}}>
                <input id="am-pwd" name="password" type={show?'text':'password'}
                  placeholder="Minimum 6 characters"
                  value={password} onChange={onPassword} onBlur={()=>setTouched(p=>({...p,password:true}))}
                  style={{...IS(touched.password&&errs.password, touched.password&&!errs.password&&password), paddingRight:44}}
                  autoComplete={mode==='login'?'current-password':'new-password'}/>
                <button type="button" onClick={()=>setShow(!show)}
                  style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'var(--t2)',cursor:'pointer',fontSize:15,padding:2}}>
                  {show?'🙈':'👁'}
                </button>
              </div>
              {/* Strength bar — register only */}
              {mode==='register' && password.length>0 && (
                <div style={{marginTop:6}}>
                  <div style={{display:'flex',gap:4}}>
                    {[1,2,3,4].map(i=>(
                      <div key={i} style={{flex:1,height:3,borderRadius:99,background:i<=strength?sColor:'var(--border2)',transition:'background .3s'}}/>
                    ))}
                  </div>
                  <span style={{fontSize:11,color:sColor,fontWeight:600,marginTop:3,display:'block'}}>{sLabel}</span>
                </div>
              )}
            </F>

            {/* Confirm Password */}
            {mode==='register' && (
              <F id="am-conf" label="Confirm Password"
                err={touched.confirm && errs.confirm}
                ok={touched.confirm && !errs.confirm && confirm ? 'Passwords match ✓' : ''}>
                <div style={{position:'relative'}}>
                  <input id="am-conf" name="confirmPassword" type={showC?'text':'password'}
                    placeholder="Repeat your password"
                    value={confirm} onChange={onConfirm} onBlur={()=>setTouched(p=>({...p,confirm:true}))}
                    style={{...IS(touched.confirm&&errs.confirm, touched.confirm&&!errs.confirm&&confirm), paddingRight:44}}
                    autoComplete="new-password"/>
                  <button type="button" onClick={()=>setShowC(!showC)}
                    style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'var(--t2)',cursor:'pointer',fontSize:15,padding:2}}>
                    {showC?'🙈':'👁'}
                  </button>
                </div>
              </F>
            )}

            {/* Submit */}
            <button type="submit" disabled={loading}
              style={{width:'100%',justifyContent:'center',padding:'13px',fontSize:15,marginTop:4,borderRadius:'var(--r2)',background:'var(--g-brand)',color:'#fff',border:'none',cursor:loading?'not-allowed':'pointer',fontFamily:'var(--ff-b)',fontWeight:700,display:'flex',alignItems:'center',gap:8,boxShadow:'0 4px 16px rgba(99,102,241,.4)',transition:'all .2s',opacity:loading?.7:1}}>
              {loading
                ? <><span className="spinner" style={{borderTopColor:'#fff'}}/>{mode==='login'?' Signing in…':' Creating account…'}</>
                : mode==='login' ? '→ Sign In' : '→ Create Account'
              }
            </button>
          </form>

          <div style={{textAlign:'center',marginTop:18,fontSize:13,color:'var(--t2)'}}>
            {mode==='login'
              ? <>Don't have an account?{' '}<button type="button" onClick={()=>onSwitch('register')} style={{background:'none',border:'none',color:'var(--indigo)',cursor:'pointer',fontWeight:700,fontSize:13}}>Register free</button></>
              : <>Already have an account?{' '}<button type="button" onClick={()=>onSwitch('login')} style={{background:'none',border:'none',color:'var(--indigo)',cursor:'pointer',fontWeight:700,fontSize:13}}>Sign in</button></>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
